Here are the public test cases for feature1_3_reusable_custom_word_lists:
{
  "description": "Evaluate one or more passwords against custom word lists that are registered once and reused across checks.",
  "cases": [
    {
      "input": {
        "word_lists": {
          "custom": [
            "words"
          ]
        },
        "passwords": [
          "password"
        ]
      },
      "expected_output": "password=password\npassword=password\nentropy=0.0\ncrack_time=0.0\ncrack_time_display=instant\nscore=0\nmatch_count=1\nmatch0.pattern=dictionary\nmatch0.token=password\n"
    }
  ]
}

Here are the public test cases for feature2_feedback_messages:
{
  "description": "Return warning and suggestion lines that explain why a tested password is weak or omit feedback when the score is good.",
  "cases": [
    {
      "input": {
        "password": "5815A30BE798"
      },
      "expected_output": "warning=none\nsuggestion_count=0\n"
    },
    {
      "input": {
        "password": "password"
      },
      "expected_output": "warning=This is a top-10 common password\nsuggestion=Add another word or two. Uncommon words are better.\nsuggestion_count=1\n"
    },
    {
      "input": {
        "password": "1qaz"
      },
      "expected_output": "warning=Straight rows of keys are easy to guess\nsuggestion=Add another word or two. Uncommon words are better.\nsuggestion=Use a longer keyboard pattern with more turns\nsuggestion_count=2\n"
    }
  ]
}

Here are the public test cases for feature3_1_dictionary_word_matches:
{
  "description": "Find dictionary terms inside a password and return each matched token, normalized word, and rank.",
  "cases": [
    {
      "input": {
        "dictionary": "custom",
        "words": [
          "test",
          "AB10CD"
        ],
        "password": "AB10CD"
      },
      "expected_output": "match_count=1\nmatch0.token=AB10CD\nmatch0.matched_word=ab10cd\nmatch0.rank=2\n"
    }
  ]
}

Here are the public test cases for feature3_3_numeric_year_date_matches:
{
  "description": "Find digit runs, years, and separated calendar dates in a password and return normalized date fields when present.",
  "cases": [
    {
      "input": {
        "password": "testing1239xx9712"
      },
      "expected_output": "match_count=2\nmatch0.pattern=digits\nmatch0.token=1239\nmatch1.pattern=digits\nmatch1.token=9712\n"
    },
    {
      "input": {
        "password": "testing02/12/1997"
      },
      "expected_output": "match_count=3\nmatch0.pattern=date\nmatch0.token=02/12/1997\nmatch0.separator=/\nmatch0.day=2\nmatch0.month=12\nmatch0.year=1997\nmatch1.pattern=digits\nmatch1.token=1997\nmatch2.pattern=year\nmatch2.token=1997\n"
    }
  ]
}

Here are the public test cases for feature4_1_entropy_estimates:
{
  "description": "Calculate entropy estimates for individual recognized pattern samples using their relevant attributes.",
  "cases": [
    {
      "input": {
        "samples": [
          {
            "kind": "repeat",
            "token": "2222"
          },
          {
            "kind": "digits",
            "token": "12345678"
          },
          {
            "kind": "date",
            "year": 2012,
            "separator": "/"
          }
        ]
      },
      "expected_output": "kind=repeat\nentropy=5.321928094887363\n---\nkind=digits\nentropy=26.5754247590989\n---\nkind=date\nentropy=17.433976574415976\n"
    }
  ]
}

Here are the public test cases for feature4_2_crack_time_display_and_score:
